export interface Song {
  id: string;
  title: string;
  artist: string;
  album: string;
  albumId: string;
  duration: string;
  youtubeUrl: string;
  trackNumber: number;
}

export interface Album {
  id: string;
  title: string;
  artist: string;
  coverUrl: string;
  year: number;
  colors: [string, string]; // two dominant colors for gradient
  songs: Song[];
}

export interface Playlist {
  id: string;
  name: string;
  description: string;
  coverUrl?: string;
  songIds: string[];
}

